def render_lesson(lesson_id: int) -> bool:
    lesson = LESSONS.get(lesson_id)
    if not lesson:
        st.error(f"Lesson 3.{lesson_id} not found.")
        return False

    already_done = is_lesson_complete(TRACK_ID, lesson_id)

    # Render concept: handle sentinels and HTML elements
    concept = lesson["concept"]
    if "[[META_PROMPT_DIAGRAM]]" in concept:
        import streamlit.components.v1 as components
        from components.diagrams import get_diagram, get_diagram_height
        parts = concept.split("[[META_PROMPT_DIAGRAM]]")
        for i, part in enumerate(parts):
            if part.strip():
                if "<img " in part or "<div " in part:
                    st.markdown(part, unsafe_allow_html=True)
                else:
                    st.markdown(part)
            if i < len(parts) - 1:
                st.markdown("<br>", unsafe_allow_html=True)
                html = get_diagram("meta_prompt_diagram")
                height = get_diagram_height("meta_prompt_diagram")
                if html:
                    components.html(html, height=height, scrolling=False)
                st.markdown("<br>", unsafe_allow_html=True)
    elif "<img " in concept or "<div " in concept:
        st.markdown(concept, unsafe_allow_html=True)
    else:
        st.markdown(concept)
    st.markdown("---")

    if already_done:
        # For sandbox and challenge lessons, render the component so output is visible.
        # The component handles its own completed state display.
        # Only short-circuit here for quiz-only lessons.
        if lesson.get("sandbox") or lesson.get("challenge"):
            pass  # fall through to the component renderers below
        else:
            st.success("✓ Lesson complete")
            return True

    # 3.1: comparison sandbox
    if lesson.get("sandbox") and lesson["sandbox"]["type"] == "comparison":
        sb = lesson["sandbox"]
        return render_comparison_sandbox(
            track_id=TRACK_ID, lesson_id=lesson_id,
            weak_prompt=sb["weak_prompt"], instruction=sb["instruction"],
        )

    # 3.2: single-attempt graded challenge
    if lesson.get("challenge") and lesson["challenge"].get("single_attempt"):
        ch = lesson["challenge"]
        return render_graded_challenge(
            track_id=TRACK_ID, lesson_id=lesson_id,
            scenario=ch["scenario"], broken_example=ch["broken_example"],
            rubric=ch["rubric"], model_answer=ch["model_answer"],
            hints=ch["hints"], input_label="Your prompt", max_chars=600,
            single_attempt=True,
        )

    # 3.4: standard sandbox then quiz
    if lesson.get("sandbox") and lesson["sandbox"]["type"] == "standard":
        sb = lesson["sandbox"]
        sandbox_done = render_sandbox(
            track_id=TRACK_ID, lesson_id=lesson_id,
            starter_prompt=sb["starter_prompt"], instruction=sb["instruction"],
        )
        if not sandbox_done:
            return False
        if lesson.get("quiz"):
            return render_quiz(
                track_id=TRACK_ID, lesson_id=lesson_id,
                questions=lesson["quiz"], label="Knowledge check",
            )
        return sandbox_done

    # 3.5: graded sandbox then quiz
    if lesson.get("sandbox") and lesson["sandbox"]["type"] == "graded":
        sb = lesson["sandbox"]
        sandbox_done = render_graded_challenge(
            track_id=TRACK_ID, lesson_id=lesson_id,
            scenario=sb["scenario"], broken_example="",
            rubric=sb["rubric"], model_answer=sb["model_answer"],
            hints=sb["hints"], input_label="Your meta-prompt", max_chars=500,
            single_attempt=True, mark_complete=False,
        )
        if not sandbox_done:
            return False
        if lesson.get("quiz"):
            return render_quiz(
                track_id=TRACK_ID, lesson_id=lesson_id,
                questions=lesson["quiz"], label="Knowledge check",
            )
        return sandbox_done

    # Quiz-only lessons (3.3, 3.5, 3.6, 3.7)
    if lesson.get("quiz") and not lesson.get("challenge"):
        return render_quiz(
            track_id=TRACK_ID, lesson_id=lesson_id,
            questions=lesson["quiz"], label="Knowledge check",
        )

    # Standard graded challenge (3.8)
    if lesson.get("challenge"):
        ch = lesson["challenge"]
        return render_graded_challenge(
            track_id=TRACK_ID, lesson_id=lesson_id,
            scenario=ch["scenario"], broken_example=ch["broken_example"],
            rubric=ch["rubric"], model_answer=ch["model_answer"],
            hints=ch["hints"], input_label="Your prompt", max_chars=700,
            single_attempt=False,
        )

    st.info("Content coming soon.", icon="🔜")
    return False
